export const loadAsyncJs = obj => {
  Object.entries(obj).forEach(entry => {
    // let key = entry[0];
    let value = entry[1];
    // console.log("key: " + key + " = " + value + " / " + typeof value);
    var script = document.createElement("script");
    script.src = value;

    script.onload = () => {
      //   console.log("onload.args: ", arguments);
    };

    script.onerror = e => {
      //   console.log("onerror.args: ", arguments);
    };

    document.head.appendChild(script);
  });
};

//

export const loadSyncJs = (scriptUrl, callback) => {
  var script = document.createElement("script");
  script.src = scriptUrl;

  script.onload = () => {
    // console.log(scriptUrl + " loaded, ready for action");

    if (callback) {
      callback(scriptUrl, true); // succeed
    }
  };

  script.onerror = e => {
    // console.log(scriptUrl + " failed to load !");

    if (callback) {
      callback(scriptUrl, false); // failed
    }
  };

  document.head.appendChild(script);
};

